## Follow 목록 조회 쿼리 최적화 가이드

### 1. Entity 설계

```kotlin
// Follow Entity 구조
@Entity
@Table(catalog = "maum", name = "follow")
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    // 팔로워 (팔로우하는 사용자)
    @Column(nullable = false)
    val followerId: String,

    // 팔로잉 (팔로우되는 사용자)
    @Column(nullable = false)
    val followingId: String,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// 인덱스 전략 (DB 마이그레이션에서 설정)
// CREATE UNIQUE INDEX idx_follow_follower_following ON follow(follower_id, following_id);
// CREATE INDEX idx_follow_follower_id ON follow(follower_id);
// CREATE INDEX idx_follow_following_id ON follow(following_id);
```

### 2. Repository 및 QueryDSL 구현

```kotlin
interface FollowRepository : JpaRepository<FollowEntity, String>, 
    QuerydslPredicateExecutor<FollowEntity> {
    // 기본 쿼리
    fun findByFollowerId(followerId: String): List<FollowEntity>
    fun findByFollowingId(followingId: String): List<FollowEntity>
    fun existsByFollowerIdAndFollowingId(followerId: String, followingId: String): Boolean
}

// QueryDSL 구현체
@Repository
class FollowQueryDslRepository(
    private val jpaQueryFactory: JPAQueryFactory
) {
    private val follow = QFollowEntity.followEntity

    // 최적화된 팔로잉 목록 조회 (페이지네이션)
    fun findFollowingList(
        followerId: String,
        pageable: Pageable
    ): Page<FollowDto> {
        val total = jpaQueryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetchOne() ?: 0L

        val content = jpaQueryFactory
            .select(
                Projections.constructor(
                    FollowDto::class.java,
                    follow.id,
                    follow.followerId,
                    follow.followingId,
                    follow.createdAt
                )
            )
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        return PageImpl(content, pageable, total)
    }

    // 최적화된 팔로워 목록 조회
    fun findFollowerList(
        followingId: String,
        pageable: Pageable
    ): Page<FollowDto> {
        val total = jpaQueryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followingId.eq(followingId))
            .fetchOne() ?: 0L

        val content = jpaQueryFactory
            .select(
                Projections.constructor(
                    FollowDto::class.java,
                    follow.id,
                    follow.followerId,
                    follow.followingId,
                    follow.createdAt
                )
            )
            .from(follow)
            .where(follow.followingId.eq(followingId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        return PageImpl(content, pageable, total)
    }

    // 상호 팔로우 확인
    fun findMutualFollows(
        userId: String,
        otherUserIds: List<String>
    ): Map<String, Boolean> {
        val results = jpaQueryFactory
            .select(
                follow.followingId,
                ExpressionUtils.`as`(
                    JPAExpressions.selectOne()
                        .from(follow)
                        .where(
                            follow.followerId.eq(otherUserIds[0])
                                .and(follow.followingId.eq(userId))
                        )
                        .exists(),
                    "isMutual"
                )
            )
            .from(follow)
            .where(
                follow.followerId.eq(userId)
                    .and(follow.followingId.`in`(otherUserIds))
            )
            .fetch()

        return otherUserIds.associate { id ->
            id to (results.find { it.get(0) == id } != null)
        }
    }
}
```

### 3. 성능 최적화 포인트

#### A. N+1 문제 방지
- 문제: 팔로우 목록을 조회할 때 각 팔로우마다 사용자 정보를 추가 조회
- 해결: Projection을 사용하여 필요한 컬럼만 조회

#### B. 페이지네이션 필수
```kotlin
// 나쁜 예: 대량 데이터 한번에 로드
fun findAllFollows(): List<FollowEntity> {
    return followRepository.findAll()
}

// 좋은 예: 페이지네이션 적용
fun findFollows(userId: String, page: Int, size: Int): Page<FollowDto> {
    return followQueryDslRepository.findFollowingList(
        userId, 
        PageRequest.of(page, size, Sort.by("createdAt").descending())
    )
}
```

#### C. 인덱스 전략
```sql
-- 필수 인덱스
CREATE UNIQUE INDEX idx_follow_unique ON follow(follower_id, following_id);
CREATE INDEX idx_follow_follower_id ON follow(follower_id);
CREATE INDEX idx_follow_following_id ON follow(following_id);

-- 추가 최적화 (복합 인덱스)
CREATE INDEX idx_follow_follower_created ON follow(follower_id, created_at DESC);
CREATE INDEX idx_follow_following_created ON follow(following_id, created_at DESC);
```

