### 5. 테스트 (TDD 접근)

```kotlin
@DataJpaTest
class FollowQueryDslRepositoryTest(
    @Autowired private val followQueryDslRepository: FollowQueryDslRepository,
    @Autowired private val followRepository: FollowRepository,
    @Autowired private val entityManager: EntityManager
) {

    @Test
    fun testFindFollowingList_shouldReturnPaginatedResults() {
        // Red: 테스트 작성
        val userId = "user-1"
        val pageable = PageRequest.of(0, 10)

        // Green: 구현
        val result = followQueryDslRepository.findFollowingList(userId, pageable)

        // Verify
        assertThat(result.content).isNotEmpty()
        assertThat(result.totalElements).isGreaterThan(0)
    }

    @Test
    fun testFindFollowingList_shouldNotCauseN1() {
        // N+1 쿼리 검증
        val userId = "user-1"
        val pageable = PageRequest.of(0, 10)

        // QueryCounter를 사용하여 쿼리 수 검증
        val initialQueryCount = getCurrentQueryCount()
        val result = followQueryDslRepository.findFollowingList(userId, pageable)
        val finalQueryCount = getCurrentQueryCount()

        // 최대 2개 쿼리만 허용 (count + fetch)
        assertThat(finalQueryCount - initialQueryCount).isLessThanOrEqualTo(2)
    }
}
```

